mapper.select:
SELECT
    forecast_at AS "forecastAt",
    forecast_value AS "forecastValue",
    confidence AS "confidence",
    model_id AS "modelId",
    risk_level AS "riskLevel"
FROM follow_up_metric_forecast
WHERE register_id = #{registerId}
  AND metric_code = #{metricCode}
AND forecast_at::date >= #{from}
AND forecast_at::date <= #{to}
ORDER BY forecast_at ASC
